431: Http::FilterHeadersStatus Filter::decodeHeaders(Http::RequestHeaderMap& headers, bool end_stream) {
432:   downstream_headers_ = &headers;
433: 
434:   // Extract debug configuration from filter state. This is used further along to determine whether
435:   // we should append cluster and host headers to the response, and whether to forward the request
436:   // upstream.
437:   const StreamInfo::FilterStateSharedPtr& filter_state = callbacks_->streamInfo().filterState();
438:   const DebugConfig* debug_config = filter_state->getDataReadOnly<DebugConfig>(DebugConfig::key());
439: 
440:   // TODO: Maybe add a filter API for this.
441:   grpc_request_ = Grpc::Common::isGrpcRequestHeaders(headers);
442:   exclude_http_code_stats_ = grpc_request_ && config_->suppress_grpc_request_failure_code_stats_;
443: 
444:   // Only increment rq total stat if we actually decode headers here. This does not count requests
445:   // that get handled by earlier filters.
446:   stats_.rq_total_.inc();
447: 
448:   // Initialize the `modify_headers` function as a no-op (so we don't have to remember to check it
449:   // against nullptr before calling it), and feed it behavior later if/when we have cluster info
450:   // headers to append.
451:   std::function<void(Http::ResponseHeaderMap&)> modify_headers = [](Http::ResponseHeaderMap&) {};
452: 
453:   // Determine if there is a route entry or a direct response for the request.
454:   route_ = callbacks_->route();
455:   if (!route_) {
456:     stats_.no_route_.inc();
457:     ENVOY_STREAM_LOG(debug, "no route match for URL '{}'", *callbacks_, headers.getPathValue());
458: 
459:     callbacks_->streamInfo().setResponseFlag(StreamInfo::CoreResponseFlag::NoRouteFound);
460:     callbacks_->sendLocalReply(Http::Code::NotFound, "", modify_headers, absl::nullopt,
461:                                StreamInfo::ResponseCodeDetails::get().RouteNotFound);
462:     return Http::FilterHeadersStatus::StopIteration;
463:   }
464: 
465:   // Determine if there is a direct response for the request.
466:   const auto* direct_response = route_->directResponseEntry();
467:   if (direct_response != nullptr) {
468:     stats_.rq_direct_response_.inc();
469:     direct_response->rewritePathHeader(headers, !config_->suppress_envoy_headers_);
470:     callbacks_->sendLocalReply(
471:         direct_response->responseCode(), direct_response->responseBody(),
472:         [this, direct_response,
473:          &request_headers = headers](Http::ResponseHeaderMap& response_headers) -> void {
474:           std::string new_uri;
475:           if (request_headers.Path()) {
476:             new_uri = direct_response->newUri(request_headers);
477:           }
478:           // See https://tools.ietf.org/html/rfc7231#section-7.1.2.
479:           const auto add_location =
480:               direct_response->responseCode() == Http::Code::Created ||
481:               Http::CodeUtility::is3xx(enumToInt(direct_response->responseCode()));
482:           if (!new_uri.empty() && add_location) {
483:             response_headers.addReferenceKey(Http::Headers::get().Location, new_uri);
484:           }
485:           direct_response->finalizeResponseHeaders(response_headers, callbacks_->streamInfo());
486:         },
487:         absl::nullopt, StreamInfo::ResponseCodeDetails::get().DirectResponse);
488:     return Http::FilterHeadersStatus::StopIteration;
489:   }
490: 
491:   // A route entry matches for the request.
492:   route_entry_ = route_->routeEntry();
493:   // If there's a route specific limit and it's smaller than general downstream
494:   // limits, apply the new cap.
495:   retry_shadow_buffer_limit_ =
496:       std::min(retry_shadow_buffer_limit_, route_entry_->retryShadowBufferLimit());
497:   if (debug_config && debug_config->append_cluster_) {
498:     // The cluster name will be appended to any local or upstream responses from this point.
499:     modify_headers = [this, debug_config](Http::ResponseHeaderMap& headers) {
500:       headers.addCopy(debug_config->cluster_header_.value_or(Http::Headers::get().EnvoyCluster),
501:                       route_entry_->clusterName());
502:     };
503:   }
504:   Upstream::ThreadLocalCluster* cluster =
